        {"name": "Recruiters", "attributes": ["recruiter_id (PK)", "user_id (FK)", "company_id (FK)", "designation"]},
        {"name": "Notifications", "attributes": ["notification_id (PK)", "user_id (FK)", "type", "message", "target_url", "is_read", "created_at"]},
