      {"method": "POST", "path": "/events", "description": "Create a new event"},
      {"method": "GET", "path": "/events", "description": "View all events"},
      {"method": "GET", "path": "/reports", "description": "Generate custom reports"}
    ],
    "general_endpoints": [
